const SUPABASE_URL=window.__ENV__?.SUPABASE_URL||'https://pzcgvfhppglzfjavxuid.supabase.co';const SUPABASE_ANON_KEY=window.__ENV__?.SUPABASE_ANON_KEY||'';let supabaseClient=null;export function initSupabase(){if(supabaseClient)return supabaseClient;if(typeof window.supabase!=='undefined'&&typeof window.supabase.createClient==='function'){supabaseClient=window.supabase.createClient(SUPABASE_URL,SUPABASE_ANON_KEY);}return supabaseClient;}export function getClient(){if(!supabaseClient){return initSupabase();}return supabaseClient;}if(typeof document!=='undefined'){document.addEventListener('DOMContentLoaded',()=>{initSupabase();});}export const supabase=getClient();if(typeof window.SupabaseAPI!=='undefined'){export const AuthAPI=window.AuthAPI;export const AdminAPI=window.AdminAPI;export const KPIAPI=window.KPIAPI;export const BinhPhapAPI=window.BinhPhapAPI;}export const auth={async getSession(){if(!supabaseClient)return null;try{const{data:{session}}=await supabaseClient.auth.getSession();return session;}catch(error){return null;}},async getUser(){if(!supabaseClient)return null;try{const{data:{user}}=await supabaseClient.auth.getUser();return user;}catch(error){return null;}},async signIn(email,password){if(!supabaseClient)return{error: 'Not initialized'};return await supabaseClient.auth.signInWithPassword({email,password});},async signOut(){if(!supabaseClient)return{error: 'Not initialized'};return await supabaseClient.auth.signOut();}};export const projects={async getAll(filters={}){if(!supabaseClient)return [];let query=supabaseClient.from('projects').select('*');if(filters.status)query=query.eq('status',filters.status);if(filters.type)query=query.eq('type',filters.type);if(filters.limit)query=query.limit(filters.limit);const{data}=await query.order('created_at',{ascending: false});return data||[];},async getById(id){if(!supabaseClient)return null;const{data}=await supabaseClient.from('projects').select('*').eq('id',id).single();return data;}};export const invoices={async getAll(filters={}){if(!supabaseClient)return [];let query=supabaseClient.from('invoices').select('*');if(filters.status)query=query.in('status',filters.status);if(filters.client_id)query=query.eq('client_id',filters.client_id);const{data}=await query.order('created_at',{ascending: false});return data||[];},async getById(id){if(!supabaseClient)return null;const{data}=await supabaseClient.from('invoices').select('*').eq('id',id).single();return data;}};export const activities={async getRecent(limit=10){if(!supabaseClient)return [];const{data}=await supabaseClient .from('activity_logs').select('*').order('created_at',{ascending: false}).limit(limit);return data||[];}};export const utils={formatCurrency:(amount)=>new Intl.NumberFormat('vi-VN',{style: 'currency',currency: 'VND'}).format(amount),timeAgo:(isoString)=>{const seconds=Math.floor((new Date()-new Date(isoString))/1000);const intervals={year: 31536000,month: 2592000,week: 604800,day: 86400,hour: 3600,minute: 60};for(const [unit,secondsInUnit] of Object.entries(intervals)){const interval=Math.floor(seconds/secondsInUnit);if(interval>=1)return `${interval}${unit}trước`;}return 'Vừa xong';}};